import{_ as t,o as a,c as i,ag as l}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Conflict Handling","description":"","frontmatter":{},"headers":[],"relativePath":"flashql/conflict-model.md","filePath":"flashql/conflict-model.md"}'),o={name:"flashql/conflict-model.md"};function s(n,e,r,c,h,p){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="conflict-handling" tabindex="-1">Conflict Handling <a class="header-anchor" href="#conflict-handling" aria-label="Permalink to &quot;Conflict Handling&quot;">​</a></h1><p>FlashQL <a href="/flashql/federation-and-sync">sync</a> is designed around predictable conflict behavior.</p><p>The system has a clear model for when a local write can still be applied and when it has lost the race to newer authoritative state. What FlashQL doesn&#39;t do is automatic merge. That would be bad &quot;magic&quot;.</p><hr><h2 id="what-a-conflict-usually-means" tabindex="-1">What a Conflict Usually Means <a class="header-anchor" href="#what-a-conflict-usually-means" aria-label="Permalink to &quot;What a Conflict Usually Means&quot;">​</a></h2><p>A conflict usually means one of these:</p><ul><li>another client already updated the row</li><li>another client already deleted the row</li></ul><p>and so, the origin row version no longer matches the version the view knows.</p><p>These scenarios are expected sync outcomes, not mysterious events.</p><h3 id="example-conflict-scenarios" tabindex="-1">Example Conflict Scenarios <a class="header-anchor" href="#example-conflict-scenarios" aria-label="Permalink to &quot;Example Conflict Scenarios&quot;">​</a></h3><p>These are the typical cases to keep in mind.</p><h4 id="update-vs-update" tabindex="-1">Update vs Update <a class="header-anchor" href="#update-vs-update" aria-label="Permalink to &quot;Update vs Update&quot;">​</a></h4><ul><li>two offline clients both update the same row</li><li>one reconnects first to apply upstream</li><li>the second reconnects later</li></ul><h4 id="delete-vs-update" tabindex="-1">Delete vs Update <a class="header-anchor" href="#delete-vs-update" aria-label="Permalink to &quot;Delete vs Update&quot;">​</a></h4><ul><li>one client deletes while offline</li><li>the other updates the same row and reconnects first</li><li>the earlier delete later tries to apply</li></ul><h4 id="update-vs-delete" tabindex="-1">Update vs Delete <a class="header-anchor" href="#update-vs-delete" aria-label="Permalink to &quot;Update vs Delete&quot;">​</a></h4><ul><li>one client updates while offline</li><li>the other deletes the same row and reconnects first</li><li>the earlier update later tries to apply</li></ul><hr><h2 id="conflict-handling-1" tabindex="-1">Conflict Handling <a class="header-anchor" href="#conflict-handling-1" aria-label="Permalink to &quot;Conflict Handling&quot;">​</a></h2><p>FlashQL sync is built around a single rule of thumb:</p><blockquote><p>If two clients both edit the same row, you do not want the latter to silently overwrite the former.</p></blockquote><p>You want the system to say, in effect:</p><blockquote><p>&quot;when a row has evolved past the version you last saw, do not overwrite&quot; &quot;apply this write only if the origin row is still the version you think it is&quot;</p></blockquote><p>That is the heart of FlashQL&#39;s conflict model.</p><h3 id="the-conflict-detection-model-row-versioning" tabindex="-1">The Conflict Detection Model: Row Versioning <a class="header-anchor" href="#the-conflict-detection-model-row-versioning" aria-label="Permalink to &quot;The Conflict Detection Model: Row Versioning&quot;">​</a></h3><p>A write back to the origin table should succeed only if the origin row is still the exact version the view holds a reference to. Should the origin row be one or more commits ahead of the view, a write back to that row should fail with a conflict error.</p><p>For this to work, incoming rows must carry with them a &quot;version&quot; tag into the view. A write back to the origin uses the tag to assert that the row hasn&#39;t evolved past the version it holds a reference to.</p><p>This &quot;row-version&quot; idea is native to MVCC-based – Multi-Version Concurrency Control – database systems like PostgreSQL and FlashQL. FlashQL sync <em>automatically</em> infers a row&#39;s version from the row&#39;s internal <code>XMIN</code> tag. <strong>Conflict detection becomes automatic.</strong></p><p>For non-MVCC-based systems like MySQL, a custom &quot;version&quot; column must be explicitly created and manually managed on the origin table. (The custom &quot;version&quot; column idea is also allowed for MVCC-based setups where that&#39;s desired.)</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE TABLE public.blog (</span></span>
<span class="line"><span style="color:#C3E88D;">    id INT PRIMARY KEY,</span></span>
<span class="line"><span style="color:#C3E88D;">    content TEXT,</span></span>
<span class="line"><span style="color:#C3E88D;">    author_name TEXT,</span></span>
<span class="line"><span style="color:#C3E88D;">    _custom_row_version BIGINT</span></span>
<span class="line"><span style="color:#C3E88D;">  );</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This column must be of type <code>BIGINT</code>.</p><p>The chosen column name must be passed to the view at creation time:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE REALTIME VIEW public.users AS</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT * FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  WITH (</span></span>
<span class="line"><span style="color:#C3E88D;">    replication_origin = &#39;postgres:primary&#39;,</span></span>
<span class="line"><span style="color:#C3E88D;">    upstream_mvcc_key = &#39;_custom_row_version&#39;</span></span>
<span class="line"><span style="color:#C3E88D;">  );</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This tells FlashQL over which column to compare row version.</p><p>For non-MVCC-based systems like MySQL, not specifying an <code>upstream_mvcc_key</code> defaults the write behaviour to:</p><blockquote><p>update row <code>id = 1</code></p></blockquote><p>Meaning:</p><blockquote><p>&quot;update anyway; last-writer-wins&quot;</p></blockquote><p>With row versioning, that instead becomes:</p><blockquote><p>update row <code>id = 1</code> only if it is still version <code>13297</code></p></blockquote><p>That difference is what makes conflict handling predictable.</p><ul><li>conflicts are explicit</li><li>data loss is avoided</li><li>the app can react intentionally</li></ul><h3 id="what-happens-on-conflict" tabindex="-1">What Happens on Conflict <a class="header-anchor" href="#what-happens-on-conflict" aria-label="Permalink to &quot;What Happens on Conflict&quot;">​</a></h3><p>If the version no longer matches:</p><ul><li>the write operation is rejected</li><li>the write attempt is marked as <code>conflicted</code> on the view&#39;s control plane table</li><li>origin state remains authoritative</li><li>the view eventually catches up with the commit that caused the divergence (This happens via an explicit refresh or via inbound sync – in the case of realtime views.)</li></ul><h3 id="what-happens-on-success" tabindex="-1">What Happens on Success <a class="header-anchor" href="#what-happens-on-success" aria-label="Permalink to &quot;What Happens on Success&quot;">​</a></h3><p>On version equality pass:</p><ul><li>the write operation is applied</li><li>the write attempt is marked as <code>applied</code> on the view&#39;s control plane table</li><li>origin table dispatches a commit event that may echo back to the view, in the case of realtime views</li><li>the view catches up via that event (inbound sync), or via an explicit refresh</li></ul><hr><h2 id="how-this-relates-to-write-policies" tabindex="-1">How This Relates to Write Policies <a class="header-anchor" href="#how-this-relates-to-write-policies" aria-label="Permalink to &quot;How This Relates to Write Policies&quot;">​</a></h2><p>Conflict detection works with both write policies, but the user experience differs.</p><h3 id="origin-first-–-the-default" tabindex="-1"><code>origin_first</code> – the Default <a class="header-anchor" href="#origin-first-–-the-default" aria-label="Permalink to &quot;\`origin_first\` – the Default&quot;">​</a></h3><ul><li>local writes are queued and dispatched async</li><li>the view&#39;s visible state <strong>waits until</strong> either: <ul><li>inbound sync echos back the change – for realtime views</li><li>the view is explicitly refreshed</li></ul></li></ul><h3 id="local-first" tabindex="-1"><code>local_first</code> <a class="header-anchor" href="#local-first" aria-label="Permalink to &quot;\`local_first\`&quot;">​</a></h3><ul><li>local writes are staged as visible rows <strong>immediately</strong></li><li>the row carries <code>__staged = true</code> until either: <ul><li>inbound sync echos back the change – for realtime views</li><li>the view is explicitly refreshed</li></ul></li></ul><p>In a conflict scenario, the view self-normalizes on an explicit refresh or via inbound sync.</p><p>The difference between the policies is really <strong>the view&#39;s immediate state until normalization</strong>.</p><hr><h2 id="observable-conflict-behavior" tabindex="-1">Observable Conflict Behavior <a class="header-anchor" href="#observable-conflict-behavior" aria-label="Permalink to &quot;Observable Conflict Behavior&quot;">​</a></h2><p><code>db.sync</code> emits a dedicated <code>conflict</code> event for these cases.</p><p>That lets applications observe conflict as its own operational category instead of as generic errors. (See <a href="/flashql/sync-api#observable-sync-events">Observable Sync Events</a>)</p><p>This can be useful for inspection and debugging.</p><hr><h2 id="what-conflict-handling-is-not" tabindex="-1">What Conflict Handling Is Not <a class="header-anchor" href="#what-conflict-handling-is-not" aria-label="Permalink to &quot;What Conflict Handling Is Not&quot;">​</a></h2><p>FlashQL explicitly doesn&#39;t do:</p><ul><li>arbitrary semantic merges</li><li>domain-specific reconciliation logic</li></ul><p>What it does is narrower and more useful:</p><ul><li>when a replicated writable view has a usable origin version token, FlashQL can detect and classify write races predictably</li></ul><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the broader sync story</td><td style="text-align:left;"><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></td></tr><tr><td style="text-align:left;">the runtime sync API</td><td style="text-align:left;"><a href="/flashql/sync-api">The Sync API</a></td></tr><tr><td style="text-align:left;">where sync fits into larger application shapes</td><td style="text-align:left;"><a href="/guides/integration-patterns">Integration Patterns</a></td></tr></tbody></table>`,71)])])}const f=t(o,[["render",s]]);export{u as __pageData,f as default};
